// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {


	if(isLoading){
		showHideFields();
		return;
	}

	//If you set it to a value that hide fields, but the original did not, the fields are hidden, but don't get redisplayed 
	//if(newValue!=oldValue){ 
		showHideFields();
	//}

	function showHideFields() {
		var strView = g_form.getViewName();

		var isStandard = g_scratchpad.taskType == 'Standard';
		var isAcknowledgement = g_scratchpad.taskType ==  'Acknowledgement';
		var isInformation_only = g_scratchpad.taskType == 'Information Only';
		// 2.8.0 - TODO - Multi-language - need to have task type value and display value
		// DFCT0011152 - bruned again, need to get these labels into values.  story created.
		var isApproval_with_Signature = g_scratchpad.taskType == 'Approval with Signature';
		var isApproval = g_scratchpad.taskType == 'Approval';
		var isConcur_with_Signature = g_scratchpad.taskType == 'Concurrence with Signature';
		var isConcur = g_scratchpad.taskType == 'Concurrence';

		//Duration fields
		// DFCT0011152 
		if(g_form.getControl('work_start')){
			g_form.setDisplay("work_start", (!isAcknowledgement && !isInformation_only));
		}
		if(g_form.getControl('work_end')){
			g_form.setDisplay("work_end", (!isAcknowledgement && !isInformation_only));
		}
		if(g_form.getControl('expected_start')){
			g_form.setDisplay("expected_start", (!isAcknowledgement && !isInformation_only));
		}
		if(g_form.getControl('calendar_duration')){
			g_form.setDisplay("calendar_duration", (!isAcknowledgement && !isInformation_only));
		}
		//Assignment fields
		// DFCT0011152 
		if(g_form.getControl('u_reviewer')){
			g_form.setDisplay("u_reviewer", (!isAcknowledgement && !isInformation_only));
		}

		//Risk section
		// DFCT0011152 
		if(g_form.getControl('risk')){
			g_form.setSectionDisplay('risk', (!isAcknowledgement && !isInformation_only));
		}

		//STRY0086943 - Response & Reviewer Decision section
		var inAssigned = (g_scratchpad.currentState == "1");
		var inUnassigned = (g_scratchpad.currentState == "-5");
		var inWaiting = (g_scratchpad.currentState == "-3");
		var inNew = (g_scratchpad.currentState == ("New" || ""));

		var standardEarlyState = (isStandard && (inUnassigned || inWaiting || inNew));
		var isReviewType = isApproval_with_Signature || isApproval || isConcur_with_Signature ||isConcur;
		var reviewtypeEarlyState = isReviewType && (inAssigned || inUnassigned || inWaiting || inNew);
		var earlyState = standardEarlyState || reviewtypeEarlyState;

		// DFCT0011152 
		var response = '';
		if(g_form.getControl('response')){
			response = g_form.getValue('response');
		}
		var rework_comments = '';
		if(g_form.getControl('rework_comments')){
			rework_comments = g_form.getValue('rework_comments');
		}
		var decision = '';
		if(g_form.getControl('decision')){
			decision = g_form.getValue('decision');
		}
		var comments_dt = '';
		if(g_form.getControl('comments_dt')){
			comments_dt = g_form.getValue('comments_dt');
		}
		var u_cancellation_reason = '';
		if(g_form.getControl('u_cancellation_reason')){
			u_cancellation_reason = g_form.getValue('u_cancellation_reason');
		}
		var earlyStateWithComments = ((earlyState ) && (response != '' 
													|| rework_comments != ''
													|| decision != ''	
													|| comments_dt != ''
													|| u_cancellation_reason != '' )
									);
		// DFCT0010951
		var showComment = ((!isAcknowledgement && !isInformation_only) && (earlyStateWithComments || !earlyState));
alert("testing debugger");
debugger;
		var reviewRequired = false;
		if(g_form.getControl('provide_response') && g_form.getValue('provide_response')==true){
			reviewRequired=true;
		}
		var showResponseSection = (reviewRequired && isStandard) || showComment;
		g_form.setSectionDisplay('response_reviewerdecision', showResponseSection);

		// Review Required
		if(g_form.getControl('provide_response')){
			g_form.setDisplay("provide_response", isStandard);
		}
	}
}
